mapper.delete:
/* com.educare.edu.comn.mapper.LectureEtcIemDataMapper.deleteByRcept */
	delete from t_lecture_etc_iem_data
	where edu_seq = #{eduSeq} and user_id = #{userId}

mapper.select:
/* com.educare.edu.comn.mapper.LectureEtcIemDataMapper.selectByRcept */
	select * from t_lecture_etc_iem_data
	where edu_seq = #{eduSeq} and user_id = #{userId}
	order by etc_iem_seq

/* com.educare.edu.comn.mapper.LectureEtcIemDataMapper.selectByEdu */
	select * from t_lecture_etc_iem_data
	where edu_seq = #{eduSeq}
	order by user_id,etc_iem_seq
